import sys
class Node:
    def __init__(self, value):
        self.value = value
        self.next = None

class Queue:
    def __init__(self):
        self.head = None
        self.tail = None

    def enqueue(self, value):
        node = Node(value)
        if self.tail is None:
            self.head = node
            self.tail = node
        else:
            self.tail.next = node
            self.tail = node

    def dequeue(self):
        if self.head is None:
            return None
        value = self.head.value
        self.head = self.head.next
        return value

def main():
    q = Queue()
    n = int(input())
    for _ in range(n):
        q.enqueue(int(input()))
    for _ in range(n):
        print(q.dequeue())

if __name__ == '__main__':
    main()

