class Solution {
   public:
      Node *head, *tail;
      void enqueue(int value) {
         Node *node = new Node(value);
         if (head == nullptr) {
            head = node;
            tail = node;
         } else {
            tail->next = node;
            tail = node;
         }
      }
      int dequeue() {
         if (head == nullptr) {
            return -1;
         }
         int value = head->value;
         Node *temp = head;
         head = head->next;
         delete temp;
         return value;
      }
};

class Node {
